# Now write to biology.json and _bundle.json
with open('public/data/grades/5/biology.json', 'r') as f:
    bio = json.load(f)

with open('public/data/grades/5/_bundle.json', 'r') as f:
    bundle = json.load(f)

# Add games to biology.json
bio['games'] = all_games

# Add games to _bundle.json
if 'biology' in bundle:
    bundle['biology']['games'] = all_games
else:
    # Find the key
    for key in bundle:
        if isinstance(bundle[key], dict) and 'lessons' in bundle[key]:
            if bundle[key]['lessons'].get('title') == 'Биология':
                bundle[key]['games'] = all_games
                break

# Write files
with open('public/data/grades/5/biology.json', 'w') as f:
    json.dump(bio, f, ensure_ascii=False, indent=2)

with open('public/data/grades/5/_bundle.json', 'w') as f:
    json.dump(bundle, f, ensure_ascii=False, indent=2)

print("Successfully wrote biology.json and _bundle.json with 43 games!")
